INSERT INTO `fabricantes` (`id`, `name`, `logo_base64`, `info`, `responsavel_id`, `file_url`) VALUES
(8, 'DAHUA', 'data:image/png;base64,', '<h3>Passo a Passo para Registro de Projetos Dahua</h3><p>&nbsp;</p><p><strong>1. Acesse o Portal de Parceiros:</strong> Primeiro, você precisa acessar o portal de parceiros da Dahua. Se você ainda não tem um cadastro, é necessário se registrar.</p><p><strong>2. Navegue até a Área de Registro de Projetos:</strong> Uma vez logado, procure pela seção de \"Registro de Projetos\" ou \"Project Registration\". Essa área geralmente fica no menu principal ou em uma seção dedicada a parceiros e programas de incentivo.</p><p><strong>3. Preencha o Formulário de Registro:</strong> O formulário solicitará informações detalhadas sobre o projeto. Preencha todos os campos com a maior precisão possível:</p><p><strong>Informações do Projeto:</strong></p><p><strong>Nome do Projeto:</strong> Um nome claro e descritivo.</p><p><strong>Localização:</strong> Endereço completo onde o projeto será implementado.</p><p><strong>Segmento de Mercado:</strong> Por exemplo, varejo, educação, governo, etc.</p><p><strong>Data de Conclusão Estimada:</strong> Quando o projeto deve ser finalizado.</p><p><strong>Valor Estimado do Projeto:</strong> O valor total da solução.</p><p><strong>Informações do Cliente Final:</strong></p><p><strong>Nome da Empresa:</strong> Nome da empresa que irá adquirir e usar os produtos.</p><p><strong>Informações de Contato:</strong> Nome, e-mail e telefone do contato principal na empresa cliente.</p><p><strong>Informações dos Produtos Dahua:</strong></p><p><strong>Produtos e Quantidades:</strong> Liste os produtos Dahua que serão utilizados, como câmeras, NVRs, software, etc., e suas respectivas quantidades. Isso é crucial para o registro.</p><p><strong>4. Envie o Formulário:</strong> Após preencher tudo, revise as informações e envie o formulário.</p><p>&nbsp;</p><h3>O que acontece depois do registro?</h3><p>&nbsp;</p><p><strong>Análise:</strong> A equipe da Dahua irá analisar as informações do seu projeto. Eles verificam se o projeto atende aos critérios do programa, se os produtos listados são adequados, e se não há duplicidade de registro por outro parceiro.</p><p><strong>Aprovação:</strong> Se o projeto for aprovado, você receberá uma notificação. A aprovação geralmente garante benefícios como preços especiais, suporte técnico dedicado e exclusividade para aquele projeto por um determinado período.</p><p><strong>Acompanhamento:</strong> Mantenha contato com seu gestor de contas na Dahua para acompanhar o status do projeto e receber o suporte necessário.</p>', NULL, NULL),
(9, 'dnet', 'data:image/png;base64,', '<p>dasdas</p>', NULL, NULL);
